class Solution:
    def triangleType(self, nums):
        a, b, c = sorted(nums)
        if a + b <= c:
            return 'none'
        distinct = len(set(nums))
        if distinct == 1:
            return 'equilateral'
        if distinct == 2:
            return 'isosceles'
        return 'scalene'

