class Solution:
    def triangleType(self, nums):
        s = sorted(nums)
        if s[0] + s[1] <= s[2]:
            return 'none'
        if s[0] == s[2]:
            return 'equilateral'
        if s[0] == s[1] or s[1] == s[2]:
            return 'isosceles'
        return 'scalene'

