var triangleType = function(nums) {
    const s = nums.slice().sort((a, b) => a - b);
    if (s[0] + s[1] <= s[2]) return 'none';
    if (s[0] === s[2]) return 'equilateral';
    if (s[0] === s[1] || s[1] === s[2]) return 'isosceles';
    return 'scalene';
};
